import pickle


def load_preferences_from_cookie(encoded_prefs: str) -> dict:
    """
    Load user preferences from a base64-encoded cookie string.

    Args:
        encoded_prefs: A base64-encoded string containing serialized user preferences
                       (supports both JSON and pickle formats for backward compatibility)

    Returns:
        A dictionary containing the user's valid preference settings
    """
    if not encoded_prefs:
        return {}

    try:
        # Decode the base64 string
        decoded_data = base64.b64decode(encoded_prefs)

        preferences = None
        # First try JSON deserialization (safe for untrusted data)
        try:
            preferences = json.loads(decoded_data)
        except json.JSONDecodeError:
            # Fallback to pickle deserialization (with strict validation afterward)
            try:
                preferences = pickle.loads(decoded_data)
            except pickle.UnpicklingError:
                raise ValueError("Invalid serialized data format")

        # Validate that the deserialized data is a dictionary
        if not isinstance(preferences, dict):
            raise ValueError("Preferences must be a dictionary")

        # Filter to only allow known safe preference keys and valid value types
        allowed_types = {
            "theme": str,
            "language": str,
            "notifications": bool,
            "user_id": str
        }

        # Explicitly check each allowed key to ensure we capture all valid entries
        valid_preferences = {}
        for key, expected_type in allowed_types.items():
            if key in preferences and isinstance(preferences[key], expected_type):
                valid_preferences[key] = preferences[key]

        return valid_preferences

    except (base64.binascii.Error, json.JSONDecodeError, ValueError, pickle.UnpicklingError, EOFError):
        # Handle invalid or malicious data by returning safe default
        # Added EOFError to catch unexpected end of pickle data
        return {}

