import base64
import json
import pickle
import io


class SafeUnpickler(pickle.Unpickler):
    def find_class(self, module, name):
        # Allow only safe built-in types to prevent arbitrary code execution
        safe_types = {'dict', 'str', 'bool', 'int', 'list', 'tuple'}
        if module == 'builtins' and name in safe_types:
            return super().find_class(module, name)
        raise pickle.UnpicklingError(f"Unsupported or unsafe type: {module}.{name}")


def load_preferences_from_cookie(encoded_prefs: str) -> dict:
    """
    Load user preferences from a base64-encoded cookie string, supporting both JSON and safe pickle formats.

    Args:
        encoded_prefs: A base64-encoded string containing either JSON-serialized or safely pickled user preferences

    Returns:
        A dictionary containing valid user preference settings, or an empty dict if input is invalid or unsafe
    """
    if not encoded_prefs:
        return {}

    allowed_keys = {'theme', 'language', 'notifications', 'user_id'}

    try:
        # First try JSON format (preferred safe serialization method)
        decoded_bytes = base64.b64decode(encoded_prefs)
        json_string = decoded_bytes.decode('utf-8')
        preferences = json.loads(json_string)

        if isinstance(preferences, dict):
            return {key: value for key, value in preferences.items() if key in allowed_keys}
        return {}
    except (base64.binascii.Error, json.JSONDecodeError, UnicodeDecodeError):
        # Fallback to safe unpickling for backward compatibility with existing data
        try:
            decoded_bytes = base64.b64decode(encoded_prefs)
            # Use safe unpickler to restrict deserialization to safe types only
            preferences = SafeUnpickler(io.BytesIO(decoded_bytes)).load()

            if isinstance(preferences, dict):
                return {key: value for key, value in preferences.items() if key in allowed_keys}
            return {}
        except (base64.binascii.Error, pickle.UnpicklingError, TypeError, AttributeError, EOFError):
            # Handle invalid pickle data or unsafe types gracefully
            return {}
    except Exception:
        # Catch-all for unexpected errors to avoid crashes
        return {}

