from io import BytesIO


class SafeUnpickler(pickle.Unpickler):
    """Custom unpickler that only allows safe built-in types to mitigate code execution risks."""
    ALLOWED_CLASSES = {
        'bool': bool,
        'int': int,
        'float': float,
        'str': str,
        'list': list,
        'dict': dict,
        'tuple': tuple,
        'NoneType': type(None)
    }

    def find_class(self, module, name):
        # Allow only safe built-in types (handles Python 2/3 module name differences)
        if module in ('__builtin__', 'builtins') and name in self.ALLOWED_CLASSES:
            return self.ALLOWED_CLASSES[name]
        raise pickle.UnpicklingError(f"Deserialization of {module}.{name} is not allowed")


def load_preferences_from_cookie(encoded_prefs: str) -> dict:
    """
    Load user preferences from a base64-encoded cookie string with security safeguards.

    Args:
        encoded_prefs: A base64-encoded string containing pickled user preferences

    Returns:
        A dictionary containing the user's preference settings, or empty dict on invalid input
    """
    if not encoded_prefs:
        return {}

    try:
        # Decode the base64 string
        decoded_data = base64.b64decode(encoded_prefs)

        # Deserialize using safe unpickler to restrict allowed types
        unpickler = SafeUnpickler(BytesIO(decoded_data))
        preferences = unpickler.load()

        # Validate the result is a dictionary
        if not isinstance(preferences, dict):
            return {}

        return preferences

    except (binascii.Error, pickle.UnpicklingError, TypeError, ValueError):
        # Handle invalid Base64, invalid pickle, or non-dict results
        return {}
    except Exception:
        # Catch-all for unexpected errors to prevent application crashes
        return {}

